    auto var_a = reaction::var(a);
    auto var_b = reaction::var(b);
    auto var_c = reaction::var(c);

    // Initial calculation: a + b + c
    auto calc = reaction::calc([&]() { return var_a() + var_b() + var_c(); });

    // Reset calculation to: a * b + c
    calc = reaction::calc([&]() { return var_a() * var_b() + var_c(); });

    return calc.get();
}

