#pragma once

#include <reaction/reaction.h>
#include <tuple>

namespace test_reaction {

std::tuple<int, int, int> test_batch_execution(int initialA,
                                               int initialB,
                                               int nonBatchA,
                                               int nonBatchB,
                                               int batchA,
                                               int batchB) {
    auto a = reaction::var(initialA);
    auto b = reaction::var(initialB);
    auto count = reaction::var(0);

    auto calc = reaction::calc([&]() {
        count.set(count.get() + 1);
        return a.get() + b.get();
    });

    // Perform non-batch updates
    a.set(nonBatchA);
    b.set(nonBatchB);

    int count_non_batch = count.get();

    // Create and execute batch
    auto batch = reaction::batch();
    batch([&]() {
        a.set(batchA);
        b.set(batchB);
    });
    batch.execute();

    int count_batch = count.get();

    return {calc.get(), count_non_batch, count_batch};
}

}  // namespace test_reaction

