    ConditionalSharedMutex mutex;

    bool trySharedWithoutSafety = mutex.try_lock_shared();
    if (trySharedWithoutSafety) {
        mutex.unlock_shared();
    }

    bool tryUniqueWhileSharedWithoutSafety = false;
    {
